16: import "github.com/prometheus/prometheus/util/features"
17: 
18: // RegisterFeatures registers all PromQL features with the feature registry.
19: // This includes operators (arithmetic and comparison/set), aggregators (standard
20: // and experimental), and functions.
21: func (pql *promQLParser) RegisterFeatures(r features.Collector) {
22: 	// Register core PromQL language keywords.
23: 	for keyword, itemType := range key {
24: 		if itemType.IsKeyword() {
25: 			switch keyword {
26: 			case "anchored", "smoothed":
27: 				r.Set(features.PromQL, keyword, pql.options.EnableExtendedRangeSelectors)
28: 			case "fill", "fill_left", "fill_right":
29: 				r.Set(features.PromQL, keyword, pql.options.EnableBinopFillModifiers)
30: 			default:
31: 				r.Enable(features.PromQL, keyword)
32: 			}
33: 		}
34: 	}
35: 
36: 	// Register operators.
37: 	for o := ItemType(operatorsStart + 1); o < operatorsEnd; o++ {
38: 		if o.IsOperator() {
39: 			r.Set(features.PromQLOperators, o.String(), true)
40: 		}
41: 	}
42: 
43: 	// Register aggregators.
44: 	for a := ItemType(aggregatorsStart + 1); a < aggregatorsEnd; a++ {
45: 		if a.IsAggregator() {
46: 			experimental := a.IsExperimentalAggregator() && !pql.options.EnableExperimentalFunctions
47: 			r.Set(features.PromQLOperators, a.String(), !experimental)
48: 		}
49: 	}
50: 
51: 	// Register functions.
52: 	for f, fc := range Functions {
53: 		r.Set(features.PromQLFunctions, f, !fc.Experimental || pql.options.EnableExperimentalFunctions)
54: 	}
55: 
56: 	// Register experimental parser features.
57: 	r.Set(features.PromQL, "duration_expr", pql.options.ExperimentalDurationExpr)
58: }
